 1	import * as React from 'react';
 2	import { ObjectCheck, ValidationTypes } from '../../types/IstioObjects';
 3	import { Validation } from './Validation';
 4	import { highestSeverity } from '../../types/ServiceInfo';
 5	import { Stack, StackItem } from '@patternfly/react-core';
 6	import { kialiStyle } from 'styles/StyleUtils';
 7	import { PFColors } from '../Pf/PfColors';
 8	
 9	type ValidationStackProps = {
10	  checks?: ObjectCheck[];
11	};
12	
13	const colorStyle = kialiStyle({ color: PFColors.White });
14	const titleStyle = kialiStyle({ color: PFColors.White, fontWeight: 'bold' });
15	
16	export const ValidationStack: React.FC<ValidationStackProps> = (props: ValidationStackProps) => {
17	  const validationList = (): React.ReactNode[] => {
18	    return (props.checks ?? []).map((check, index) => {
19	      return (
20	        <StackItem key={`validation-check-item-${index}`} className={colorStyle}>
21	          <Validation
22	            key={`validation-check-${index}`}
23	            severity={check.severity}
24	            message={`${check.code ? `${check.code} ` : ''}${check.message}`}
25	          />
26	        </StackItem>
27	      );
28	    });
29	  };
30	
31	  const severity = highestSeverity(props.checks ?? []);
32	  const isValid = severity === ValidationTypes.Correct;
33	
34	  if (!isValid) {
35	    return (
36	      <Stack>
37	        <StackItem className={titleStyle}>Istio validations</StackItem>
38	        {validationList()}
39	      </Stack>
40	    );
41	  } else {
42	    return null;
43	  }
44	};

